MAX_LINES = 50
MAX_CHARS = 3000

def read_log_file(path: str) -> dict:
    """Return a structured summary of a log file, not its full content."""
    try:
        with open(path) as f:
            lines = f.readlines()
    except FileNotFoundError:
        return {"error": "NOT_FOUND", "message": f"Log file not found: {path}"}

    total_lines = len(lines)
    errors   = [l.strip() for l in lines if "ERROR" in l]
    warnings = [l.strip() for l in lines if "WARN" in l]
    tail     = [l.strip() for l in lines[-MAX_LINES:]]

    return {
        "path": path,
        "total_lines": total_lines,
        "error_count": len(errors),
        "warning_count": len(warnings),
        "recent_errors": errors[-5:],          # last 5 errors, not all of them
        "last_50_lines": tail,
        "note": (
            f"Showing last {MAX_LINES} lines and last 5 errors of {total_lines} total. "
            "Use read_log_section(path, start_line, end_line) to read specific ranges."
        ),
    }

def read_log_section(path: str, start_line: int, end_line: int) -> dict:
    """Read a specific line range from a log file."""
    end_line = min(end_line, start_line + 100)  # hard cap per call
    try:
        with open(path) as f:
            all_lines = f.readlines()
    except FileNotFoundError:
        return {"error": "NOT_FOUND", "message": f"{path} not found"}

    chunk = all_lines[start_line:end_line]
    return {
        "path": path,
        "start_line": start_line,
        "end_line": start_line + len(chunk),
        "lines": [l.rstrip() for l in chunk],
    }

import csv, io, uuid, time
from pathlib import Path

_EXPORT_DIR = Path("/tmp/agent_exports")
_EXPORT_DIR.mkdir(exist_ok=True)
_EXPORTS: dict[str, dict] = {}

def export_orders_csv(
    customer_id: str,
    date_from: str,
    date_to: str,
) -> dict:
    """Generate a CSV export and return a reference, not the file contents."""
    orders = _fetch_orders(customer_id, date_from, date_to)  # could be thousands

    export_id = str(uuid.uuid4())[:8]
    filename = f"orders_{customer_id}_{export_id}.csv"
    filepath = _EXPORT_DIR / filename

    fieldnames = ["order_id", "date", "total_usd", "status"]
    with open(filepath, "w", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for o in orders:
            writer.writerow({k: o[k] for k in fieldnames})

    _EXPORTS[export_id] = {
        "path": str(filepath),
        "row_count": len(orders),
        "created_at": time.time(),
    }

    return {
        "export_id": export_id,
        "filename": filename,
        "row_count": len(orders),
        "message": (
            f"Export ready: {len(orders)} orders written to {filename}. "
            "Use read_export_preview(export_id) to inspect the first rows, "
            "or provide the filename as a download link to the user."
        ),
    }

def read_export_preview(export_id: str, max_rows: int = 10) -> dict:
    meta = _EXPORTS.get(export_id)
    if not meta:
        return {"error": "NOT_FOUND", "message": f"No export with id {export_id}"}
    with open(meta["path"], newline="") as f:
        reader = csv.DictReader(f)
        rows = [row for _, row in zip(range(max_rows), reader)]
    return {
        "export_id": export_id,
        "preview_rows": rows,
        "total_rows": meta["row_count"],
    }

def _fetch_orders(customer_id, date_from, date_to):
    return [{"order_id": f"ord_{i}", "date": date_from,
             "total_usd": 9.99 * i, "status": "shipped"} for i in range(250)]

from typing import Any

_ALL_PRODUCT_FIELDS = {
    "id", "name", "sku", "price_usd", "stock", "category",
    "description", "weight_kg", "dimensions_cm", "supplier_id",
    "warehouse_location", "created_at", "updated_at", "tags",
}

_DEFAULT_FIELDS = {"id", "name", "price_usd", "stock", "category"}

def get_product(
    product_id: str,
    fields: list[str] | None = None,
) -> dict:
    """
    Fetch a product record.
    fields: list of field names to return. Defaults to a concise subset.
    """
    raw = _fetch_product(product_id)
    if raw is None:
        return {"error": "NOT_FOUND", "message": f"No product: {product_id}"}

    requested = set(fields) if fields else _DEFAULT_FIELDS
    invalid = requested - _ALL_PRODUCT_FIELDS
    if invalid:
        return {
            "error": "INVALID_FIELDS",
            "invalid": sorted(invalid),
            "available": sorted(_ALL_PRODUCT_FIELDS),
        }

    return {k: raw[k] for k in requested if k in raw}

def _fetch_product(pid: str) -> dict | None:
    return {f: f"val_{pid}_{f}" for f in _ALL_PRODUCT_FIELDS} | {"price_usd": 49.99, "stock": 12}

MAX_ROWS      = 15
MAX_FIELD_LEN = 200

_SEARCHABLE_FIELDS = {"id", "title", "author", "published_at", "summary"}

def search_articles(
    query: str,
    fields: list[str] | None = None,
    cursor: int = 0,
    limit: int = MAX_ROWS,
) -> dict:
    limit = min(limit, MAX_ROWS)
    selected = set(fields) if fields else {"id", "title", "published_at", "summary"}
    selected &= _SEARCHABLE_FIELDS   # silently drop unknown fields

    raw_hits = _run_search(query)    # returns all matches, potentially thousands
    total = len(raw_hits)
    page  = raw_hits[cursor : cursor + limit]
    next_cursor = cursor + limit if cursor + limit < total else None

    items = []
    for hit in page:
        item: dict[str, Any] = {}
        for field in selected:
            val = hit.get(field, "")
            item[field] = str(val)[:MAX_FIELD_LEN] if isinstance(val, str) else val
        items.append(item)

    return {
        "query": query,
        "total_hits": total,
        "returned": len(items),
        "cursor": cursor,
        "next_cursor": next_cursor,
        "has_more": next_cursor is not None,
        "articles": items,
    }

def _run_search(q: str) -> list[dict]:
    return [
        {"id": f"art_{i}", "title": f"Article {i} about {q}",
         "author": "Alice", "published_at": "2026-07-01",
         "summary": "x" * 500, "body": "y" * 50000}   # body omitted by projection
        for i in range(80)
    ]

