def test_field_projection_excludes_unknown():
    result = get_product("prod_1", fields=["id", "name", "nonexistent"])
    assert result["error"] == "INVALID_FIELDS"
    assert "nonexistent" in result["invalid"]

def test_field_projection_returns_only_requested():
    result = get_product("prod_1", fields=["id", "price_usd"])
    assert set(result.keys()) == {"id", "price_usd"}

def test_result_under_char_budget():
    result = search_articles("python", limit=15)
    serialised = json.dumps(result)
    assert len(serialised) < 4000, f"Result too large: {len(serialised)} chars"

def test_export_returns_reference_not_content():
    result = export_orders_csv("cust_1", "2026-01-01", "2026-07-01")
    assert "export_id" in result
    assert "row_count" in result
    serialised = json.dumps(result)
    assert len(serialised) < 500, "Export result should be a small reference"
